* {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
}

body {
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, "Helvetica Neue", Arial, sans-serif;
    background-color: #f5f7fa;
    min-height: 100vh;
    color: #333;
}

/* 导航栏样式 */
.navbar {
    background: linear-gradient(135deg, #667eea, #764ba2);
    color: #fff;
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 0 24px;
    height: 60px;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.15);
}

.navbar-brand {
    font-size: 20px;
    font-weight: 700;
    letter-spacing: 1px;
}

.navbar-menu {
    display: flex;
    align-items: center;
    gap: 16px;
}

.navbar-welcome {
    font-size: 14px;
    opacity: 0.95;
}

.navbar-link {
    color: #fff;
    text-decoration: none;
    font-size: 14px;
    padding: 6px 16px;
    border: 1px solid rgba(255, 255, 255, 0.5);
    border-radius: 4px;
    transition: background-color 0.2s;
}

.navbar-link:hover {
    background-color: rgba(255, 255, 255, 0.15);
}

/* 容器样式 */
.container {
    max-width: 600px;
    margin: 40px auto;
    padding: 0 16px;
}

/* 卡片样式 */
.card {
    background: #fff;
    border-radius: 8px;
    box-shadow: 0 2px 12px rgba(0, 0, 0, 0.08);
    padding: 32px;
    margin-bottom: 24px;
}

.card-center {
    text-align: center;
}

.card-title {
    font-size: 22px;
    font-weight: 600;
    margin-bottom: 16px;
    color: #333;
}

.card-subtitle {
    font-size: 16px;
    font-weight: 500;
    margin-bottom: 12px;
    color: #666;
}

.card-text {
    font-size: 15px;
    color: #666;
    margin-bottom: 20px;
}

/* 信息列表样式 */
.info-list {
    list-style: none;
    margin-bottom: 24px;
}

.info-list li {
    padding: 10px 0;
    border-bottom: 1px solid #f0f0f0;
    font-size: 15px;
}

.info-list li:last-child {
    border-bottom: none;
}

.info-label {
    font-weight: 600;
    color: #555;
    display: inline-block;
    min-width: 80px;
}

/* 表单样式 */
.login-form {
    margin-top: 8px;
}

.form-group {
    margin-bottom: 20px;
}

.form-group label {
    display: block;
    font-size: 14px;
    font-weight: 500;
    color: #555;
    margin-bottom: 6px;
}

.form-input {
    width: 100%;
    padding: 10px 12px;
    border: 1px solid #d0d5dd;
    border-radius: 6px;
    font-size: 15px;
    outline: none;
    transition: border-color 0.2s;
}

.form-input:focus {
    border-color: #667eea;
    box-shadow: 0 0 0 3px rgba(102, 126, 234, 0.15);
}

/* 按钮样式 */
.btn {
    display: inline-block;
    padding: 10px 24px;
    font-size: 15px;
    font-weight: 500;
    border: none;
    border-radius: 6px;
    cursor: pointer;
    text-decoration: none;
    transition: background-color 0.2s;
}

.btn-primary {
    background-color: #667eea;
    color: #fff;
    width: 100%;
}

.btn-primary:hover {
    background-color: #5a6fd6;
}

/* 错误消息样式 */
.error-message {
    background-color: #fff0f0;
    color: #d63031;
    border: 1px solid #fad1d1;
    border-radius: 6px;
    padding: 10px 14px;
    margin-bottom: 16px;
    font-size: 14px;
}

